class Solution {
public:
    int palindromePartition(string s, int k) {
        int n = s.size();
        vector<vector<bool>> dp(n, vector<bool>(n, false));
        for (int i = 0; i < n; ++i) {
            dp[i][i] = true;
        }
        for (int len = 2; len <= n; ++len) {
            for (int i = 0; i <= n - len; ++i) {
                int j = i + len - 1;
                if (s[i] == s[j] && (len == 2 || dp[i + 1][j - 1])) {
                    dp[i][j] = true;
                }
            }
        }
        int changes = 0;
        int start = 0;
        for (int i = 0; i < k; ++i) {
            int end = start;
            while (end < n && !dp[start][end]) {
                ++end;
            }
            if (end == start) {
                ++changes;
            }
            start = end + 1;
        }
        return changes;
    }
};
